const urlString = $.input.imageUrls || '';
const urls = urlString.split(',').map(function(u) { return u.trim(); }).filter(function(u) { return u.length > 0; });
return { urls: urls, count: urls.length };

const vType = $.input.validationType || 'general';
const custom = $.input.validationCriteria || '';
let criteria = '';

if (vType === 'passport_photo') {
  criteria = 'Validate as passport/ID photo: face clearly visible and centered, neutral expression, plain background (white or light grey), no shadows on face, no glasses, proper lighting, head and shoulders only, recent photo quality.';
} else if (vType === 'product_image') {
  criteria = 'Validate as product photo: product clearly visible, clean background, good lighting, no blur, product fills most of frame, no distracting elements, professional quality.';
} else if (vType === 'document_scan') {
  criteria = 'Validate as document scan: text readable, all corners visible, no significant skew, adequate resolution, no fingers or shadows blocking content.';
} else if (vType === 'id_card') {
  criteria = 'Validate as ID card photo: card fully visible, all text readable, no glare or reflections, both sides if applicable, no cropping of edges.';
} else {
  criteria = 'General image quality validation: clear and not blurry, adequate lighting, subject clearly visible, no obvious defects.';
}

if (custom) criteria += '\nAdditional criteria: ' + custom;

return { criteria: criteria, validationType: vType };

const urls = $.steps.parseImageUrls.output.urls;
const criteria = $.steps.buildValidationCriteria.output;

let prompt = 'You are an image validation specialist using AI vision. Validate the following images against specific criteria.\n\n';
prompt += 'VALIDATION TYPE: ' + criteria.validationType + '\n';
prompt += 'CRITERIA: ' + criteria.criteria + '\n\n';
prompt += 'IMAGES TO VALIDATE:\n';
urls.forEach(function(url, i) {
  prompt += (i + 1) + '. ' + url + '\n';
});
prompt += '\nFor each image, evaluate against all criteria points and provide a pass/fail assessment.\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "validationType": "' + criteria.validationType + '",\n';
prompt += '  "results": [\n';
prompt += '    {\n';
prompt += '      "imageIndex": 1,\n';
prompt += '      "url": "",\n';
prompt += '      "status": "pass|fail|review",\n';
prompt += '      "score": 0,\n';
prompt += '      "criteria": [{ "check": "criteria point", "passed": true, "note": "" }],\n';
prompt += '      "summary": "",\n';
prompt += '      "suggestions": [""]\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "overallPassRate": "0%",\n';
prompt += '  "summary": "overall validation summary"\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiValidation.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { validationType: $.input.validationType || 'general', results: [], overallPassRate: '0%', summary: raw.slice(0, 300) }; }

const ai = $.steps.parseAI.output;
const rows = [];
const results = ai.results || [];
results.forEach(function(r) {
  const criteriaText = (r.criteria || []).map(function(c) { return c.check + ': ' + (c.passed ? 'PASS' : 'FAIL'); }).join('; ');
  rows.push([
    String(r.imageIndex || ''),
    r.url || '',
    r.status || '',
    String(r.score || 0),
    r.summary || '',
    criteriaText,
    (r.suggestions || []).join(', ')
  ]);
});
return { rows: rows };

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Image Validation Results', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Validation Type:*\n' + (ai.validationType || 'general') },
  { type: 'mrkdwn', text: '*Pass Rate:*\n' + (ai.overallPassRate || 'N/A') }
] });
blocks.push({ type: 'divider' });

const results = ai.results || [];
results.slice(0, 8).forEach(function(r) {
  let statusIcon = ':white_check_mark:';
  if (r.status === 'fail') statusIcon = ':x:';
  else if (r.status === 'review') statusIcon = ':warning:';
  let text = statusIcon + ' *Image ' + (r.imageIndex || '') + ':* ' + (r.status || '').toUpperCase();
  text += ' (Score: ' + (r.score || 0) + '/100)';
  text += '\n' + (r.summary || '').slice(0, 300);
  if (r.suggestions && r.suggestions.length > 0) {
    text += '\n_Suggestions:_ ' + r.suggestions.slice(0, 2).join(', ');
  }
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
});

blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:* ' + (ai.summary || '').slice(0, 1500) } });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Saved to Google Sheets | Powered by Claude AI Vision' }] });
const fallbackText = 'Image Validation: ' + (ai.overallPassRate || '?') + ' pass rate - ' + results.length + ' images';
return { blocks, fallbackText };
